INSERT INTO public.photos VALUES (25908, 'Coso Alto ca. 1970', 'Unidad del tranv├¡a de la l├¡nea 5 Venecia-Delicias, a su paso por la confluencia del Coso Alto con la plaza de San Roque. Al fondo, edificio de La Adri├ítica. Fuente: Agencia EFE.', 1970, 1970, 1970, 'Anos 70', 'CENTRO', 41.65318500, -0.88243700, '0101000020E6100000A5F8F884EC3CECBF6F9EEA909BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24503955812.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24503955812.webp', 'https://www.flickr.com/photos/zaragozaantigua/24503955812/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25912, 'Coso Alto c.1905', 'Vista, desde cierta altura, del tramo del Coso Alto desde su emboque en la plaza de la Constituci├│n. con una interesante panor├ímica del lado de los pares, con visual de los antiguos palacios de S├ístago, del marqu├®s de Campo Franco, y del conde Fuentes. Casi a continuaci├│n, el arco de San Roque, con acceso a la plazuela del mismo nombre. Por delante de esta edilicia fachada, transita la unidad n┬║ 7, posiblemente de la tranviaria y electrificada l├¡nea 2, o "Madrid". Inmediata, en la acera de los impares, parada de galeras de alquiler, y la met├ílica estructura sobre la que se desplegaban los toldos que proteg├¡an a los comercios de ese lado de la inclemente y severa solana. Huecograbado de la serie "Arag├│n" de postales editadas por el librero Cecilio Gasca. Fuente visual: www.todocoleccion.net/', 1905, 1905, 1905, 'Anos 1900', 'CENTRO', 41.65292400, -0.88195200, '0101000020E61000008F899466F338ECBF02637D0393D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27411584795.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27411584795.webp', 'https://www.flickr.com/photos/zaragozaantigua/27411584795/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25929, 'Coso Alto 1968', 'Imagen del tramo alto del Coso desde su arranque (al fondo) y hasta la plaza de la Manter├¡a (a la izquierda, fuera de plano), con una interesante panor├ímica en los principios del verano que incluye el colegio de los PP. Escolapios, la antigua Casa de las Monas que marca el inicio de la manzana entre las calles Cerd├ín y Escuelas P├¡as, el edificio de la Audiencia Territorial, el hotel Oriente y el cine Coso, donde se proyecta la simp├ítica comedia a la espa├▒ola Cuarenta grados a la sombra, dirigida por Mariano Ozores y con destacado elenco encabezado por Jos├® Luis L├│pez V├ízquez, Alfredo Landa, Antonio Ozores, Gracita Morales, Julieta Serrano, Laly Soldevila. Centra la imagen una composici├│n tranviaria (posiblemente de la serie 50) en servicio en la l├¡nea 5 Venecia Delicias encaminada hacia la plaza de Huesca (antigua de Rocasolano). Unos pardales viajan de gratis con cierto riesgo subidos en el parachoques trasero del remolque o trabuca. A la izquierda, vista parcial del gran solar resultante del derribo de los antiguos edificios del lado de los pares comprendidos entre los n├║meros 24 y 34. Fuente visual: Colecci├│n JAHL (Zaragoza), en Zaragoza estereosc├│pica. Fotograf├¡a profesional y comercial 1850-1970, PUZ.', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.65346900, -0.88282100, '0101000020E6100000C11A67D31140ECBF94F947DFA4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37573472676.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37573472676.webp', 'https://www.flickr.com/photos/zaragozaantigua/37573472676/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20953, 'Puente del G├íllego 1824', 'Litograf├¡a dibujada por Louis Albert Guillain, Bar├│n de Bacler d''Albe en 1824. Arcadas del puente sobre el r├¡o G├íllego en Zaragoza, que se supuso romano y en realidad fue edificado entre 1563 y 1588, sito en el emplazamiento del actual puente de hierro al final de la avenida de Catalu├▒a. La caseta del cobro del peaje (izquierda) se construy├│ en 1813. A la derecha, pasarela algo m├ís modesta, de tres siglos despu├®s. Historia de Zaragoza, 1988. Fuente visual: Colecci├│n Jos├® Luis Cintora.', 1824, 1824, 1824, 'Siglo XIX', 'EL RABAL', 41.67089800, -0.84220400, '0101000020E6100000AAEE91CD55F3EABFD57954FCDFD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15237850881.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15237850881.webp', 'https://www.flickr.com/photos/zaragozaantigua/15237850881/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20993, 'R├¡o G├íllego 1820', 'Plano de la porci├│n del r├¡o G├íllego en el Camino Real a Barcelona (abajo a la derecha) y Santa Isabel. Est├í dibujado el antiguo puente de piedra renacentista que se encontraba derruido, sirviendo de dique involuntario para desviar las aguas del r├¡o. Fuente: Centro Geogr├ífico del Ej├®rcito.', 1820, 1820, 1820, 'Siglo XIX', 'EL RABAL', 41.67107800, -0.84236800, '0101000020E61000003C4D66BCADF4EABF558847E2E5D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31369321281.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31369321281.webp', 'https://www.flickr.com/photos/zaragozaantigua/31369321281/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21194, 'Hermanos Villuendas 1893', 'Imagen capturada posiblemente bajo la estructura del puente colgante de Santa Isabel sobre el r├¡o G├íllego, y centrada en los que podr├¡an ser los hermanos Hilari├│n y Enrique Villuendas, realizando a su vez una fotograf├¡a a dos pardales. Estos dos zaragozanos, desconocidos hasta hace pocos a├▒os, pertenecen al grupo de pioneros de la fotograf├¡a en la ciudad, fundamentalmente por un impagable grupo de fotograf├¡as realizadas al hilo de la construcci├│n del edificio que albergar├¡a a la Facultad de Medicina y Ciencias (1887-1893).', 1893, 1893, 1893, 'Siglo XIX', 'EL RABAL', 41.67094000, -0.84209500, '0101000020E6100000FC00A43671F2EABF04CAA65CE1D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50278175768.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50278175768.webp', 'https://www.flickr.com/photos/zaragozaantigua/50278175768/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21582, 'Azucarera del G├íllego c.1920', 'Aspecto parcial de la Azucarera del G├íllego. Al fondo, sus dos chimeneas. Fuente: Foto Jes├║s Corm├ín. AMZ.', 1920, 1920, 1920, 'Anos 20', 'EL RABAL', 41.66970600, -0.84465800, '0101000020E6100000A9C0C9367007EBBFADF71BEDB8D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24528232779.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24528232779.webp', 'https://www.flickr.com/photos/zaragozaantigua/24528232779/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21590, 'Puente de Santa Isabel c.1920', 'Acceso desde la margen derecha del r├¡o G├íllego al puente de Santa Isabel, con tr├ínsito de un reba├▒o de ovejas. Fuente: Foto Jes├║s Corm├ín. AMZ.', 1920, 1920, 1920, 'Anos 20', 'EL RABAL', 41.67108200, -0.84225800, '0101000020E6100000766B990CC7F3EABF9677D503E6D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24803301391.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24803301391.webp', 'https://www.flickr.com/photos/zaragozaantigua/24803301391/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21597, 'Azucarera del G├íllego c.1920', 'Instalaciones de la Azucarera del G├íllego. Fuente: Foto Jes├║s Corm├ín. AMZ.', 1920, 1920, 1920, 'Anos 20', 'EL RABAL', 41.66970600, -0.84465800, '0101000020E6100000A9C0C9367007EBBFADF71BEDB8D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24896073885.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24896073885.webp', 'https://www.flickr.com/photos/zaragozaantigua/24896073885/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21652, 'Puente del G├íllego c.1925', 'Imagen capturada junto a la ribera de la margen izquierda del r├¡o G├íllego y centrada en el decimon├│nico puente colgante que salvaba el r├¡o para dar continuidad a la carretera de Madrid a Barcelona y llegar hasta Santa Isabel, y al que poco despu├®s acompa├▒ar├¡a a su izquierda un moderno puente de hierro y cemento. A su derecha, restos del antiguo puente de piedra. Al fondo y a la izquierda emerge una chimenea de la azucarera del G├íllego sita en la margen derecha.', 1925, 1925, 1925, 'Anos 20', 'EL RABAL', 41.67121200, -0.84229900, '0101000020E61000001B834E081DF4EABF64575A46EAD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51489416585.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51489416585.webp', 'https://www.flickr.com/photos/zaragozaantigua/51489416585/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21728, 'Azucarera del G├íllego 1931', 'Edificio de oficinas del complejo fabril de la Azucarera del G├íllego. Tras el edificio, el muro que delimitaba la f├íbrica en un largo tramo de la carretera de Barcelona. Fuente visual: "A Don Benito Lewin y Auser como testimonio de sincero cari├▒o y admiraci├│n, con motivo del XXV Aniversario de su matrimonio le dedican este homenaje sus subordinados: Madrid, a 25 de Diciembre de 1931", en bibliotecavirtualmadrid.org/', 1931, 1931, 1931, 'Anos 30', 'EL RABAL', 41.67029300, -0.84513000, '0101000020E610000097CADB114E0BEBBF6EDE3829CCD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21095453598.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21095453598.webp', 'https://www.flickr.com/photos/zaragozaantigua/21095453598/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22316, 'R├¡o G├íllego 1960', 'Vista a├®rea del puente sobre el r├¡o G├íllego a su paso por Zaragoza y de la entrada del barrio de Santa Isabel (abajo). Fuente visual: Arxiu Nacional de Catalunya.', 1960, 1960, 1960, 'Anos 60', 'EL RABAL', 41.67086900, -0.84209700, '0101000020E610000029E9616875F2EABF3B730F09DFD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15796511255.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15796511255.webp', 'https://www.flickr.com/photos/zaragozaantigua/15796511255/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22511, 'Vista a├®rea, c.1963', 'Vista a├®rea centrada en las antiguas instalaciones de Saica en la carretera de Huesca. Hacia el fondo, la factor├¡a de la Uni├│n Alcoholera Espa├▒ola, y los dep├│sitos de combustible de Campsa. A la derecha, gran solar reservado para la urbanizaci├│n del Grupo de Viviendas Balsas de Ebro Viejo.', 1963, 1963, 1963, 'Anos 60', 'EL RABAL', 41.67081200, -0.86982900, '0101000020E6100000A69883A0A3D5EBBFD6E1E82ADDD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51054274293.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51054274293.webp', 'https://www.flickr.com/photos/zaragozaantigua/51054274293/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22533, 'Calle Anz├ínigo 1970', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo. Enero 1970. Durante la Alcald├¡a-Presidencia de Jos├® M┬¬ S├ínchez Ventura (1946-49), se emprende la construcci├│n de la primera barriada obrera perif├®rica. Los terrenos elegidos estaban en el Picarral, entre el Camino de Juslibol y la Cra. de Huesca, donde construir un grupo de 6 manzanas con 645 viviendas ultrabaratas y varias tiendas, proyectado por los arquitectos municipales Jos├® de Yarza y Jos├® Beltr├ín. El proyecto arranca en 1947, y las obras terminaron en 1949 aunque no se adjudicaron hasta 1952. El conjunto recibi├│ el emotivo nombre de "Grupo de Viviendas Francisco FrancoÔÇØ. En la imagen, una de las calles del Grupo, denominada Anz├ínigo, con el barrizal que se formaba los d├¡as de lluvia, y posteriores.', 1970, 1970, 1970, 'Anos 70', 'EL RABAL', 41.67404100, -0.87280600, '0101000020E61000001A1538D906EEEBBFE294B9F946D64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14731401410.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14731401410.webp', 'https://www.flickr.com/photos/zaragozaantigua/14731401410/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22542, 'San Juan de la Pe├▒a c.1977', 'Transporte Oruga Acorazado M-113 pasa junto a un autob├║s urbano por la avenida de San Juan de la Pe├▒a, en el barrio del Picarral, en su trayecto proveniente de las instalaciones militares de la carretera de Huesca. Durante d├®cadas, los vecinos de la zona tuvieron que soportar el amenazante paso de todo tipo de veh├¡culos militares en sus recorridos desde la Estaci├│n del Arrabal hasta el campo de maniobras, y viceversa, como es el caso. La Asociaci├│n de Vecinos del Picarral expresaba ante las autoridades civiles y militares su rechazo a esta actividad, que imposibilitaba la urbanizaci├│n de la zona: Cada vez que que se hacen maniobras en el campo de San Gregorio, todo el equipo es descargado en la estaci├│n (del Arrabal). Las movilizaciones y el transcurso del tiempo los eliminaron del paisaje. En la imagen, y hacia la derecha, comienza el camino de los Molinos.', 1977, 1977, 1977, 'Anos 70', 'EL RABAL', 41.67228900, -0.87116300, '0101000020E610000027874F3A91E0EBBFF33AE2900DD64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14939266259.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14939266259.webp', 'https://www.flickr.com/photos/zaragozaantigua/14939266259/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22683, 'Calle del Gral. Monasterio 1979', 'Imagen capturada desde la calle Monte Perdido y centrada en la calle del General Monasterio (Grupo de Viviendas "Francisco Franco"), con el firme levantado por reformas. Al fondo, el camino de Juslibol y naves industriales de la textil CAITASA. En 2009, la denominaci├│n de esta calle fue sustituida por la de Mar├¡a Dom├¡nguez Rem├│n, pozuelera que en 1932 fue la primera mujer espa├▒ola al frente de una alcald├¡a (Gallur), y que en 1936 ser├¡a fusilada en las tapias del cementerio de Fuendejal├│n por los facciosos levantados en armas el 18-19 de julio de ese a├▒o. Fuente visual: Banco de Im├ígenes/Asociaci├│n de Vecinos Barrio de San Jos├®, amablemente cedida para el', 1979, 1979, 1979, 'Anos 70', 'EL RABAL', 41.67329800, -0.87287500, '0101000020E61000003BDF4F8D97EEEBBF2A3BFDA02ED64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26612097959.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26612097959.webp', 'https://www.flickr.com/photos/zaragozaantigua/26612097959/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22705, 'C.┬║ de Juslibol c.1970', 'Imagen del antiguo camino de Juslibol en su natural faceta de barrizal tras unas lluvias, en el tramo comprendido entre la parcela del n┬║ 20 y el Grupo de viviendas "Teniente Polanco". Al fondo, el colegio p├║blico San Braulio, algunas viviendas del Grupo de viviendas "Teniente Ortiz de Z├írate" y tras la calle del Valle de Broto, uno de los altos bloques del Grupo de viviendas "Balsas de Ebro Viejo". La chiquiller├¡a transita con ordinaria determinaci├│n hacia al cole evitando los charcos mayores y el barro blando. Fuente visual: fotosdelpicarral.blogspot.com/', 1970, 1970, 1970, 'Anos 70', 'EL RABAL', 41.66961200, -0.87390500, '0101000020E6100000BBF2599E07F7EBBF2C8194D8B5D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27807222877.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27807222877.webp', 'https://www.flickr.com/photos/zaragozaantigua/27807222877/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22710, 'Calle de San Juan de la Pe├▒a c.1970', 'Imagen capturada en la calle de San Juan de la Pe├▒a a la altura del inmueble del n├║mero 155, esquinero con la calle del General Yag├╝e. A la derecha, vista parcial de la gran factor├¡a desmotadora de la Algodonera del Ebro, donde trabajara como mec├ínico Manuel Rotellar Mata. Sobre el firme, en primer plano y entre el adoquinado, tendido viario de la l├¡nea 10 del tranv├¡a "Arrabal-Academia". En el centro de la imagen, una de las habituales zonas de agua de lluvia estancada de longeva duraci├│n en el barrio del Picarral, junto a una cabina de tel├®fono p├║blico. Fuente visual: fotosdelpicarral.blogspot.com/', 1970, 1970, 1970, 'Anos 70', 'EL RABAL', 41.67429400, -0.87145800, '0101000020E61000005BCD3AE3FBE2EBBFCCF10A444FD64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28753111818.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28753111818.webp', 'https://www.flickr.com/photos/zaragozaantigua/28753111818/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22711, 'C.┬║ de Juslibol c.1970', 'Camino de Juslibol en una imagen capturada en el tramo entre el Grupo de viviendas Teniente Polanco y la calle de Juslibol, al fondo, donde destaca la achaflanada esquina de Talleres Unidos S.A., Tusa. A la izquierda, parcelas cuyas traseras daban al campo de f├║tbol de la Federaci├│n. A la derecha, parcelas de los n├║meros 10-36 del camino, de las que perduran la n┬║ 16 y la n┬║ 14, recrecida una altura. Sobre el terroso e irregular firme, caracter├¡stico de las barriadas perif├®ricas, el autob├║s Seddon n┬║ 23 en servicio en la l├¡nea 28. Lonja-Picarral, que fue inaugurada en 1964 para sustituir a la provisional Murallas Romanas-Ortilla, establecida a su vez para paliar la supresi├│n de la pasarela de Macanaz con motivo de la construcci├│n del puente de Santiago. Fue suprimida en 1977 al integrarse su recorrido en la nueva l├¡nea 36. Valdefierro-Picarral.', 1970, 1970, 1970, 'Anos 70', 'EL RABAL', 41.66961200, -0.87390500, '0101000020E6100000BBF2599E07F7EBBF2C8194D8B5D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28770223898.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28770223898.webp', 'https://www.flickr.com/photos/zaragozaantigua/28770223898/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22757, 'San Juan de la Pe├▒a 1972', 'Imagen capturada en la avenida de San Juan de la Pe├▒a, poco antes de llegar a la enlazadora avenida del Alcalde Francisco Caballero. Al fondo, el puente de la autopista del Nordeste en construcci├│n, la f├íbrica de maquinaria CALSA, y la antigua carretera de Huesca que contin├║a ascendente en direcci├│n norte. En primer plano, obras de alcantarillado, adoquines levantados del firme y tendido tranviario de la recientemente clausurada l├¡nea 10 "Arrabal-Academia".', 1972, 1972, 1972, 'Anos 70', 'EL RABAL', 41.67704800, -0.87114800, '0101000020E6100000D2393FC571E0EBBF3EE94482A9D64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32791001713.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32791001713.webp', 'https://www.flickr.com/photos/zaragozaantigua/32791001713/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22760, 'Monte Perdido 1978', 'Imagen de la calle Monte Perdido capturada desde cierta altura (posiblemente, desde el n┬║ 11 del bloque luego denominado "Jardines de la Concordia", recayente a San Juan de la Pe├▒a), que acent├║a el impacto (desde varios puntos de vista) de las industrias inmediatas, y al norte, de la calle Somport y el Grupo de Viviendas "Francisco Franco": Gesplasmetal, y Campo Ebro. Al fondo, vista parcial de algunos de los montes militarizados en el entorno a la AGM. Fuente visual: Banco de Im├ígenes/Asociaci├│n de Vecinos Barrio de San Jos├®, amablemente cedida para el', 1978, 1978, 1978, 'Anos 70', 'EL RABAL', 41.67450000, -0.87271400, '0101000020E6100000EE5C18E945EDEBBF7593180456D64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32898657230.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32898657230.webp', 'https://www.flickr.com/photos/zaragozaantigua/32898657230/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22761, 'Av. San Juan de la Pe├▒a 1978', 'Imagen del tramo de la avenida de San Juan de la Pe├▒a que, casi desde la calle de Maella (a la derecha, fuera de plano), y hasta la avenida Alcalde Francisco Caballero (a las espaldas del fot├│grafo), fue impactado por una de las tremendas colmenas humanas realizadas en la ciudad por la famosa empresa Construcciones Colmenero SA. Al "mejor piso" en este sector, seg├║n reza el comercial, parece no acompa├▒arle una urbanizaci├│n que est├® a su vertiginosa altura. Fuente visual: Banco de Im├ígenes/Asociaci├│n de Vecinos Barrio de San Jos├®, amablemente cedida para el', 1978, 1978, 1978, 'Anos 70', 'EL RABAL', 41.67684800, -0.87090100, '0101000020E6100000E1B721C66BDEEBBF772E8CF4A2D64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32976402762.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32976402762.webp', 'https://www.flickr.com/photos/zaragozaantigua/32976402762/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22765, 'Monte Perdido 1978', 'Imagen capturada en la calle Monte Perdido, con vista parcial del Grupo de Viviendas "Francisco Franco", y el arranque de los viales General Valera (luego M┬¬ S├ínchez Arb├│s), General Moscard├│ (Luego Juan Cabrt├® Aguil├│), General Jos├® Monasterio (luego M┬¬ Dom├¡nguez Rem├│n), Batalla del Ebro (luego Arturo Bressel Marca), y Posici├│n San Sim├│n (luego Teresa Ag├╝esca). Todas estas calles, otro ejercicio de la abrumadora y oficial memoria hist├│rica del r├®gimen franquista, conflu├¡an hacia la izquierda en el Camino de Juslibol y las instalaciones de CAITASA. Al fondo, muros perimetrales de la empresa Geplasmetal. Fuente visual: Banco de Im├ígenes/Asociaci├│n de Vecinos Barrio de San Jos├®, amablemente cedida para el', 1978, 1978, 1978, 'Anos 70', 'EL RABAL', 41.67301000, -0.87276800, '0101000020E6100000BAD91F28B7EDEBBFC3F0113125D64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33225793916.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33225793916.webp', 'https://www.flickr.com/photos/zaragozaantigua/33225793916/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22794, 'Calle del General Yag├╝e c.1970', 'Imagen capturada en la calle del General Yag├╝e. A la izquierda, vista parcial del bloque del Grupo de viviendas "General Franco" (inmuebles 2 y 4), y tras la calle del Monte Perdido, la gran factor├¡a desmotadora de la Algodonera del Ebro. Al fondo, la calle de San Juan de la Pe├▒a, donde emergen las monta├▒as de paja de SAICA y el esquinero inmueble del n┬║ 155. A la derecha, parcelas de los n├║meros 1 a 19 de General Yag├╝e, incluyendo el local del mercadillo "el Pilar", y fuera de plano, traseras de la f├íbrica TUSA. El acu├ítico y terroso centro de la imagen incorpora una de las habituales escenas de las barriadas de la ciudad hasta hace no demasiado tiempo: ni├▒os que juegan en la calle interactuando libre y literalmente con cualquier elemento del entorno.', 1970, 1970, 1970, 'Anos 70', 'EL RABAL', 41.67269700, -0.87319700, '0101000020E6100000D6E3BED53AF1EBBF048F6FEF1AD64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/42731518741.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/42731518741.webp', 'https://www.flickr.com/photos/zaragozaantigua/42731518741/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23468, 'P.┬║ de Ruise├▒ores c.1950', 'Imagen de la que fuera originalmente vivienda unifamiliar de Raimundo Balet proyectada por Manuel Isasi Isasmendi en 1903 y sita en el "barrio de Ruise├▒ores", ya notablemente reformada por intervenciones como la de 1919 con dise├▒o de Miguel ├üngel Navarro P├®rez, y alguna otra posterior que le a├▒adi├│ su elemento arquitect├│nico m├ís reconocible: el modernista y esquinero torreoncillo a la izquierda de la imagen. Cuando era propiedad de Ram├│n de Pedro, esta fotograf├¡a fue realizada para publicitar el edificio como colegio de bachillerato "Los ├üngeles" en el paseo de Ruise├▒ores n┬║ 39. Tras unos a├▒os en desuso, a finales de la d├®cada de los a├▒os cincuenta el edificio cambi├│ de propietarios y fue convertido en el nuevo colegio Santo Tom├ís de Aquino de bachillerato masculino, lo que conllev├│ una ampliaci├│n edilicia en las ajardinadas traseras, y una reforma interna y de la fachada. As├¡ continu├│ hasta su clausura en 1986. Fuente visual: www.todocoleccion.net/', 1950, 1950, 1950, 'Anos 50', 'UNIVERSIDAD', 41.63651000, -0.88907700, '0101000020E61000007D06D49B5173ECBFDAC9E02879D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30474886347.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30474886347.webp', 'https://www.flickr.com/photos/zaragozaantigua/30474886347/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22939, 'Av. de Salvador Allende c.1981', 'Desde la altura de la autopista a Barcelona, vista del tramo final de la avenida de Salvador Allende hasta su desemboque en la avenida de San Juan de la Pe├▒a, a la izquierda, donde se elevan los bloques de los n├║meros 181-195 de la irracional manzana que hacia el fondo llega hasta la actual calle de Ob├│n. A su derecha e inmediatas, las descomunales instalaciones de la transformadora industrial del ma├¡z Campo Ebro Industrial, fundada en 1964 y que perdura como Tereos Syral, uno de los tradicionales focos de contaminaci├│n y malos olores del Picarral. En primer plano, terraplenes y montoneras que anuncian el inicio de las obras de urbanizaci├│n de la m├ís norte├▒a intervenci├│n del Actur-Puente de Santiago, vertebrada por la actuales calles de Federico Engels y de Jean-Paul Sartre. Junto a la carretera, una parada de la l├¡nea 29. Plaza del Pilar-Academia General Militar del autob├║s urbano reclama publicidad. Fuente visual: Banco de Im├ígenes/Asociaci├│n de Vecinos Barrio de San Jos├®, amablemente cedida para el', 1981, 1981, 1981, 'Anos 80', 'EL RABAL', 41.67810800, -0.87182200, '0101000020E6100000B1DD3D40F7E5EBBFF793313ECCD64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32857688880.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32857688880.webp', 'https://www.flickr.com/photos/zaragozaantigua/32857688880/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22941, 'Av. de San Juan de la Pe├▒a c.1981', 'Imagen capturada posiblemente desde la altura de la reciente autopista del Nordeste, con una interesante visual del entronque de las avenidas Alcalde Francisco Caballero, con la de San Juan de la Pe├▒a, y su continuaci├│n hacia la MAZ y la AGM. A la izquierda, e inmediata, la factor├¡a de maquinaria CALSA. Al fondo, chimeneas de la papelera SAICA. Esta zona fue considerada por un tiempo el "nec plus ultra" en t├®rminos de ciudad, hasta que a finales de siglo fue presentado el Plan Parcial de las ├íreas 2, 4, 5 y 6, o "Ciudad Jard├¡n Puerta de los Pirineos", luego Parque Goya I, y II. Fuente visual: Banco de Im├ígenes/Asociaci├│n de Vecinos Barrio de San Jos├®, amablemente cedida para el', 1981, 1981, 1981, 'Anos 80', 'EL RABAL', 41.67829100, -0.87109400, '0101000020E610000006BD378600E0EBBFE8154F3DD2D64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33170074526.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33170074526.webp', 'https://www.flickr.com/photos/zaragozaantigua/33170074526/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22949, 'Margen izquierda 1981', 'Ortofoto de 1981 de los barrios de la margen izquierda del r├¡o Ebro, al norte de Zaragoza: Picarral, Cogullada, Arrabal y La Jota. M├ís al norte, San Gregorio y Mercazaragoza. Fuente: Instituto Geogr├ífico de Arag├│n.', 1981, 1981, 1981, 'Anos 80', 'EL RABAL', 41.67442400, -0.87573000, '0101000020E6100000D908C4EBFA05ECBF9AD18F8653D64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39665105410.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39665105410.webp', 'https://www.flickr.com/photos/zaragozaantigua/39665105410/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23008, 'Picarral 1990', 'Imagen del antiguo campo de la Federaci├│n en el Picarral, en activo desde 1957, donde jugaban como locales aquellos equipos cercanos que carec├¡an de campo propio. En 1992, dos de ellos, el C.D. Picarral y la U.D. Balsas Ebro Viejo se unificaron en el U.D. Balsas Picarral, y a finales de esa d├®cada este campo fue derribado y construido uno de titularidad municipal, nueva planta, y orientaci├│n: de la original W-E, se pas├│ a la actual N-S. A la izquierda de la imagen, bloques de la calle Pantano de la Sotonera. Al fondo, construcciones en el entorno de la avenida de Salvador Allende y la paralela calle de Alberto Casa├▒al Shakery. A la derecha, fuera de plano, la calle de Juslibol. El lagunazo a la izquierda, resultado de la natural acumulaci├│n de precipitaciones en forma de agua. Fuente visual: Antonio Calvo Pedr├│s, AMZ.', 1990, 1990, 1990, 'Anos 90', 'EL RABAL', 41.66959600, -0.87458100, '0101000020E6100000C87E164B91FCEBBF26C45C52B5D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30740957455.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30740957455.webp', 'https://www.flickr.com/photos/zaragozaantigua/30740957455/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23009, 'Picarral c.1991', 'Imagen a├®rea del entorno de la estaci├│n de ferrocarril "Arrabal Clasificaci├│n", centrada en las instalaciones fabriles de la metal├║rgica "Rico y Echeverr├¡a S.A." (desaparecida), y la papelera "Saica" (perdura). A la derecha, el mar de v├¡as ferroviario, y el pol├¡gono "Cogullada". Fuente visual: ├üngel Gonz├ílez, a trav├®s de www.forotrenes.com/', 1991, 1991, 1991, 'Anos 90', 'EL RABAL', 41.67111000, -0.86828300, '0101000020E61000005187156EF9C8EBBF6002B7EEE6D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31005690961.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31005690961.webp', 'https://www.flickr.com/photos/zaragozaantigua/31005690961/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23034, 'Actur 1992', 'A├®rea vista del noreste del Actur con el desarrollo edilicio del momento, capturada con el fondo de la ciudad consolidada donde a la izquierda se destaca la silueta del templo del Pilar. En el centro de la escena, la Autopista del Ebro o A-2 se├▒ala de izquierda a derecha el l├¡mite del desarrollo urbano. A├▒os despu├®s, donde los campos de herb├íceas de primer t├®rmino, comenzar├í a desarrollarse el proyecto "Ciudad Jard├¡n Puerta de los Pirineos", luego Parque Goya. Vertebra la imagen de sur a norte la avenida de los Pirineos, que tras el cruce con la A-2 contin├║a como carretera de Huesca, unos a├▒os despu├®s convertida en autov├¡a. Entre las calles de Federico Engels y de las Islas Canarias se destacan todav├¡a por su decreciente soledad los pioneros centros educativos de esta perif├®rica zona de la ciudad, ambos en funcionamiento desde 1980, cuando el panorama estaba bastante m├ís despejado: el Instituto de Educaci├│n Secundaria Avempace, denominaci├│n de 1988 del original Instituto de Bachillerato Mixto n┬║ 10, durante muchos a├▒os ├║nico centro de ense├▒anzas medias de la margen izquierda; y el Colegio de Educaci├│n Infantil y Primaria Zalfonada, que comenz├│ siendo colegio Arrabal-Picarral.', 1992, 1992, 1992, 'Anos 90', 'EL RABAL', 41.67991500, -0.87824100, '0101000020E6100000E833A0DE8C1AECBFA987687407D74440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50209951253.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50209951253.webp', 'https://www.flickr.com/photos/zaragozaantigua/50209951253/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23162, 'Avenida Catalu├▒a 2007', 'Edificio de oficinas y ventas del concesionario Opel Iglesias, en la avenida de Catalu├▒a 243. Se inaugur├│ en 2007 seg├║n proyecto de J1 Arquitectos. Gan├│ el XXIX Premio Ricardo Magdalena de la Instituci├│n Fernando el Cat├│lico. Fue abandonado en 2013, y demolido en 2016. Fuente visual: j1arquitectos.com/', 2007, 2007, 2007, 'Siglo XXI', 'EL RABAL', 41.66998800, -0.84951300, '0101000020E6100000F0DB10E3352FEBBF315BB22AC2D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32549229466.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32549229466.webp', 'https://www.flickr.com/photos/zaragozaantigua/32549229466/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23258, 'Acequia Urdana c.1920', 'Molino del Mosnillo y acequia Urdana en Movera. Al fondo, puente de Santa Isabel sobre el r├¡o G├íllego. Fuente: Foto Jes├║s Corm├ín. AMZ.', 1920, 1920, 1920, 'Anos 20', 'EL RABAL', 41.66985700, -0.84089400, '0101000020E61000004CE2AC889AE8EABF93FFC9DFBDD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24796545782.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24796545782.webp', 'https://www.flickr.com/photos/zaragozaantigua/24796545782/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23743, 'Puente sobre el G├íllego c.1907', 'Se├▒ora (posiblemente ├Çngela Llinars, esposa del fot├│grafo de la imagen) cruzando el puente colgante sobre el r├¡o G├íllego. Al fondo, a la izquierda, la antigua harinera de Villarroya y Castellano, constituida en el a├▒o 1848 con ocho muelas sobre un antiguo bat├ín del siglo XVI sito en la bifurcaci├│n del camino de Monta├▒ana con el camino de Barcelona. Se incendi├│ en 1855, y dos a├▒os despu├®s fue reconstruida. En 1881 fue pionera en la introducci├│n en Espa├▒a de mejoras t├®cnicas, como el sistema austroh├║ngaro. En 1899 fue reconvertida en f├íbrica azucarera denominada "Nueva Azucarera de Zaragoza", cuya sociedad ser├¡a disuelta en 1908 por muy malos resultados econ├│micos. Fuente visual: foto Miquel Pons Bernareggi, en Arxiu Nacional de Catalunya.', 1907, 1907, 1907, 'Anos 1900', 'EL RABAL', 41.67089500, -0.84201500, '0101000020E6100000E0B9F770C9F1EABF64062AE3DFD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14923233091.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14923233091.webp', 'https://www.flickr.com/photos/zaragozaantigua/14923233091/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23751, 'Puente del G├íllego 1897', 'El G├íllego era un r├¡o que se sal├¡a de madre con natural frecuencia, llev├índose por delante puentes de madera y de piedra, fueran del tama├▒o que fueran. En 1844 se inaugur├│ una nueva modalidad, en hierro, y colgante, para salvar los 136 metros de trinchera fluvial en la estrat├®gica carretera de Madrid a Francia. Fue terminado en 1844, pero ya en 1846 tuvo que ser reparado, y en 1862 hubo que construir defensas en las m├írgenes del r├¡o. En 1869 finaliz├│ la contrata de 25 a├▒os para explotar aranceles y portazgos, y pas├│ a titularidad p├║blica. En 1871 la magna crecida del Ebro tuvo su tremendo correlato en las aguas que por aqu├¡ ven├¡an de Francia, y hubo que hacer m├ís reparaciones, como en 1878. En 1888 se plante├│ un nuevo gran proyecto, cuyo resultado es el que la imagen recoge. En los a├▒os 20 del pasado siglo este puente fue sustituido por uno nuevo, tambi├®n met├ílico, sobre cimientos hasta 15 metros por debajo del nivel del r├¡o, y capaz de soportar el creciente tr├ífico rodado. Mientras ├®ste se constru├¡a, el m├ís antiguo garantizaba la continuidad del tr├ínsito. Cuando el nuevo fue terminado e inaugurado en 1930, el viejo ser├í luego derribado. En la imagen, visual del puente colgante de Santa Isabel, mirando desde la ribera derecha. Al fondo, a la izquierda, chimenea e instalaciones de la antigua harinera de "Villarroya y Castellano", poco antes de convertirse en azucarera. A la derecha, el comienzo de los barrios de Santa Isabel, y Movera. Fuente visual: "Delimitaci├│n Comarcal de Zaragoza" (Colecci├│n Territorio), DGA, 2011.', 1897, 1897, 1897, 'Siglo XIX', 'EL RABAL', 41.67086900, -0.84209700, '0101000020E610000029E9616875F2EABF3B730F09DFD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18957678321.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18957678321.webp', 'https://www.flickr.com/photos/zaragozaantigua/18957678321/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23754, 'Puente de Santa Isabel 1844', '"Puente colgante de hierro sobre el r├¡o G├íllego, en Zaragoza. Inaugurado el d├¡a 18 de Noviembre de 1844, con el nombre de Santa Isabel", litograf├¡a de L. Cuevas para el ├ülbum art├¡stico de los grandes monumentos de Zaragoza, 1838-1844. Imagen del reci├®n construido puente de Santa Isabel sobre el r├¡o G├íllego. Fuente: ├ülbum gr├ífico de Zaragoza, 1985.', 1844, 1844, 1844, 'Siglo XIX', 'EL RABAL', 41.67086900, -0.84209700, '0101000020E610000029E9616875F2EABF3B730F09DFD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19318574589.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19318574589.webp', 'https://www.flickr.com/photos/zaragozaantigua/19318574589/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23759, 'Puente de Santa Isabel 1913', 'Foto: Lorenzo Almarza. Dos militares contemplan los bajos del puente colgante de Santa Isabel sobre el r├¡o G├íllego, en 1913. Al fondo, el barrio de Santa Isabel. Fuente: Archivo Diputaci├│n Provincial de Huesca.', 1913, 1913, 1913, 'Anos 10', 'EL RABAL', 41.67094700, -0.84216000, '0101000020E6100000C2FA3F87F9F2EABFB62C5F97E1D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21439051996.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21439051996.webp', 'https://www.flickr.com/photos/zaragozaantigua/21439051996/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23762, 'Vacas en el G├íllego c.1913', 'Vista del Puente de Santa Isabel sobre el r├¡o G├íllego, con vacas en la orilla izquierda. Fuente: "Trabajo, sociedad, cultura. Una mirada al siglo XX en Arag├│n", UGT, 2000.', 1913, 1913, 1913, 'Anos 10', 'EL RABAL', 41.67076200, -0.84186000, '0101000020E61000001CF0F96184F0EABF25B37A87DBD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23981044001.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23981044001.webp', 'https://www.flickr.com/photos/zaragozaantigua/23981044001/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23763, 'Puente Santa Isabel 1890', 'Imagen capturada durante las obras de construcci├│n del nuevo puente "colgado" (sic) de Santa Isabel sobre el r├¡o G├íllego, que ven├¡a a sustituir al anterior de mediados de siglo, bastante necesitado de reparaciones y mejoras. Fuente visual: Revista de Obras P├║blicas.', 1890, 1890, 1890, 'Siglo XIX', 'EL RABAL', 41.67076200, -0.84186000, '0101000020E61000001CF0F96184F0EABF25B37A87DBD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24211362313.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24211362313.webp', 'https://www.flickr.com/photos/zaragozaantigua/24211362313/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23769, 'Puente de Santa Isabel 1916', 'Aspecto del puente colgante sobre el r├¡o G├íllego, con el barrio de Santa Isabel al fondo, durante una carrera automovil├¡stica desde Barcelona hasta Madrid. Fuente: foto Josep Maria Co i de Triola, en Arxiu Fotogr├áfic Centre Excursionista de Catalunya.', 1916, 1916, 1916, 'Anos 10', 'EL RABAL', 41.67107800, -0.84236800, '0101000020E61000003C4D66BCADF4EABF558847E2E5D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30514280615.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30514280615.webp', 'https://www.flickr.com/photos/zaragozaantigua/30514280615/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23770, 'Puente de Santa Isabel 1917', 'Imagen del antiguo puente colgante de hierro por el que la carretera de Madrid a Francia salvaba el r├¡o G├íllego desde 1888. La captura se ha realizado desde el disminuido cauce, cuando un carro est├í cruzando a contraluz desde Santa Isabel, hacia Zaragoza. Fuente visual: Carles Batlle Ensesa, Ajuntament de Girona.', 1917, 1917, 1917, 'Anos 10', 'EL RABAL', 41.67086900, -0.84209700, '0101000020E610000029E9616875F2EABF3B730F09DFD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30998469254.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30998469254.webp', 'https://www.flickr.com/photos/zaragozaantigua/30998469254/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23778, 'Puente del G├íllego c.1905', 'Imagen del reciente puente colgante del G├íllego, por donde pasaba la carretera de Madrid a Francia. Al fondo, el barrio de Santa Isabel, en la margen izquierda de dicho r├¡o. Fuente visual: www.todocoleccion.net/', 1905, 1905, 1905, 'Anos 1900', 'EL RABAL', 41.67086900, -0.84209700, '0101000020E610000029E9616875F2EABF3B730F09DFD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33429955892.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33429955892.webp', 'https://www.flickr.com/photos/zaragozaantigua/33429955892/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23779, 'Puente de Santa Isabel 1908', 'Imagen del reciente puente colgante sobre el G├íllego, por donde pasaba la carretera de Madrid a Francia. Al fondo, el barrio rural de Santa Isabel, en la margen izquierda de dicho r├¡o, con las instalaciones de la Nueva Azucarera de Zaragoza, que fuera antigua harinera de Villarroya y Castellano. Fuente visual: "Zaragoza art├¡stica ├® industrial. Album de la Exposici├│n. 1908."', 1908, 1908, 1908, 'Anos 1900', 'EL RABAL', 41.67086900, -0.84209700, '0101000020E610000029E9616875F2EABF3B730F09DFD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33883343163.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33883343163.webp', 'https://www.flickr.com/photos/zaragozaantigua/33883343163/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23780, 'Puente sobre el G├íllego c.1913', 'Imagen capturada en el puente colgante sobre el r├¡o G├íllego, por donde transitaba la carretera de Madrid a Francia por Barcelona. Al fondo, el barrio de Santa Isabel. Esta fue la ├║ltima de las versiones de este puente colgante, ubicado en una muy antigua localizaci├│n que conoci├│ diversos modelos de puente desde al menos la Alta Edad Media. A finales de la d├®cada de los a├▒os veinte fue sustituido por un puente de nueva f├íbrica dise├▒ado para soportar el moderno tr├ífico rodado a motor de explosi├│n. Fuente visual: El fot├│grafo Luis Gand├║ Mercadal. Una cr├│nica visual 1910-1930.', 1913, 1913, 1913, 'Anos 10', 'EL RABAL', 41.67086900, -0.84209700, '0101000020E610000029E9616875F2EABF3B730F09DFD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37010935270.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37010935270.webp', 'https://www.flickr.com/photos/zaragozaantigua/37010935270/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23782, 'Puente del G├íllego c.1915', 'Imagen capturada desde la margen izquierda del r├¡o G├íllego y centrada en el hom├│nimo puente colgante. En primer t├®rmino, y aprovechando el estival bajo nivel del r├¡o, varios canteros extraen cantos rodados de la gravera fluvial, que luego cargar├ín en los carros situados en la margen derecha para emplearlos en obras varias en la ciudad. En este di├ífano espacio en 1926 se emprender├ín las obras de construcci├│n del moderno puente met├ílico tendido entre el desaparecido medieval y el puente colgante, para habilitar un paso m├ís seguro a la creciente circulaci├│n motorizada de la carretera nacional.', 1915, 1915, 1915, 'Anos 10', 'EL RABAL', 41.67087600, -0.84181600, '0101000020E610000033FCA71B28F0EABFEDD5C743DFD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/47984410946.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/47984410946.webp', 'https://www.flickr.com/photos/zaragozaantigua/47984410946/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23785, 'Puente del G├íllego viejo 1913', 'Imagen centrada en la arcada superviviente del antiguo y desaparecido medieval puente de piedra sobre el r├¡o G├íllego, junto al que en 1890 se construy├│ el moderno puente "colgado" o colgante de Santa Isabel, desde donde se ha capturado la foto en la margen derecha, no muy lejos de la azucarera del G├íllego.', 1913, 1913, 1913, 'Anos 10', 'EL RABAL', 41.67127100, -0.84260900, '0101000020E6100000A5164A26A7F6EABF69E04735ECD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51691098725.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51691098725.webp', 'https://www.flickr.com/photos/zaragozaantigua/51691098725/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24459, 'Azucarera del G├íllego 1913', 'Azucarera del G├íllego en 1913. Esta azucarera se puso en marcha en 1913 y cerr├│ en 1967. Estaba situada en la orilla del r├¡o G├íllego, en Zaragoza. En la foto vemos el puente colgante, a la izquierda. Fuente: M┬¬ Pilar Biel Ib├í├▒ez, Zaragoza y la industrializaci├│n: la arquitectura industrial 1875-1936, IFC, 2004.', 1913, 1913, 1913, 'Anos 10', 'EL RABAL', 41.66970600, -0.84465800, '0101000020E6100000A9C0C9367007EBBFADF71BEDB8D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19705751651.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19705751651.webp', 'https://www.flickr.com/photos/zaragozaantigua/19705751651/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24502, 'Picarral 1984', 'Imagen en altura desde el reciente n┬║ 7-9 de la calle Antonio Tramullas (antiguo Camino de Juslibol) del impresionante aspecto de la factor├¡a de Campo Ebro Industrial, cuya impronta sobre el barrio del Picarral era extraordinaria. Fue instalada a comienzos de la d├®cada de los a├▒os 60 como una potente iniciativa para la transformaci├│n industrial del ma├¡z. Tras la recuperaci├│n de la democracia municipal, el vecindario se moviliz├│ para solicitar su cierre y traslado. El Plan General de Ordenaci├│n Urbana aprobado en 1984, mantuvo la calificaci├│n de este suelo como "industrial", con los votos favorables de la mayor├¡a socialista, y los votos de la derecha estatal. La derecha regionalista se abstuvo, y vot├│ en contra el concejal comunista. En la imagen, parece evidente que los limpios y verdes colores con los que la empresa pint├│ sus instalaciones, no atenuaban el impacto ambiental sobre el entorno. A la derecha, los bloques de viviendas del entorno de la calle Ob├│n, y San Juan de la Pe├▒a. El humo no deja ver mucho m├ís. A la izquierda, al fondo, el complejo de la MAZ. Fuente visual: Banco de Im├ígenes Picarral fotosdelpicarral.blogspot.com.es/', 1984, 1984, 1984, 'Anos 80', 'EL RABAL', 41.67635100, -0.87361500, '0101000020E6100000F870C971A7F4EBBFF6CE68AB92D64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31087168441.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31087168441.webp', 'https://www.flickr.com/photos/zaragozaantigua/31087168441/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24504, 'San Juan de la Pe├▒a 1965', 'Imagen a├®rea sobrevolando las inmediaciones del achaflanado encuentro entre la avenida de San Juan de la Pe├▒a, que luminosa asciende rectil├¡nea desde la ciudad, al fondo, y la tranquila y alabeada calle de Francisco Alcalde Caballero que entronca con ella desde la izquierda. En ese punto, la imagen se centra en las longitudinales instalaciones fabriles de CALSA (Construcciones Agromet├ílicas de Levante, S.A.), dedicadas al montaje de gr├║as sobre veh├¡culos diversos, as├¡ como tractores, remolques y palas cargadoras. Antes, y a ambos lados de San Juan de la Pe├▒a, otras f├íbricas como Coromina Industrial, junto al camino de los Molinos, y grupos de viviendas como el de Francisco Franco, junto a la CAITASA. Fuente visual: Arxiu Nacional de Catalunya', 1965, 1965, 1965, 'Anos 60', 'EL RABAL', 41.67801200, -0.87036300, '0101000020E610000016C0948103DAEBBFD525E318C9D64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31770132461.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31770132461.webp', 'https://www.flickr.com/photos/zaragozaantigua/31770132461/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24505, 'Alcalde Caballero 1965', 'Imagen capturada sobrevolando la despejada calle del Alcalde Francisco Caballero, muy cerca del antiguo camino de Cogullada (inmediato y a la derecha, fuera de plano), centrada en las nuevas instalaciones de "Manuzac", una de las empresas pioneras del pol├¡gono de Cogullada. A la izquierda, el paso elevado que salva la l├¡nea del ferrocarril a Huesca y Canfranc, poco antes de la construcci├│n del nuevo enlace desde Miraflores. Al fondo, la zona industrial del camino de los Molinos y la Corbera Alta, el nuevo colegio de Cristo Rey, y los pabellones de la Academia General Militar junto a la carretera de Huesca. A la derecha, y al fondo, el original Sanatorio Antituberculoso del Cascajo, encaminado a su conversi├│n en hospital de especialidades en enfermedades del t├│rax. Fuente visual: Arxiu Nacional de Catalunya', 1965, 1965, 1965, 'Anos 60', 'EL RABAL', 41.67217800, -0.86143700, '0101000020E61000002C0FD253E490EBBF9C8BBFED09D64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31797966931.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31797966931.webp', 'https://www.flickr.com/photos/zaragozaantigua/31797966931/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
